DELETE FROM slots_reservados 
WHERE reservado_en < NOW() - INTERVAL '10 minutes';

SELECT COALESCE(string_agg(id_programacion::text, ', '), 'ninguno') 
  as slots_ocupados 
FROM slots_reservados;

parameters.jsCode:
