const slots = JSON.parse(output);

return [{
  json: {
    id1: slots[0].idProgramacion,
    id2: slots[1].idProgramacion,
    id3: slots[2].idProgramacion,
    documento: $('flujo_padre').first().json.documento,
    output: output
  }
}];

